<?php $h=static fn($v)=>htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');$paginationPage=max(1,(int)($paginationPage??1));$paginationTotal=max(1,(int)($paginationTotal??1));$paginationPages=is_array($paginationPages??null)?$paginationPages:[]; ?><nav class="vo-pagination" aria-label="Paginación"><span>Página <?= $paginationPage ?> de <?= $paginationTotal ?></span><div class="vo-actions"><?php if(isset($paginationPrevious)): ?><a class="vo-btn" rel="prev" href="<?= $h($paginationPrevious) ?>">Página anterior</a><?php endif; ?><?php foreach($paginationPages as$page=>$url): ?><a class="vo-btn<?= (int)$page===$paginationPage?' vo-btn--primary':'' ?>" href="<?= $h($url) ?>"<?= (int)$page===$paginationPage?' aria-current="page"':'' ?> aria-label="Página <?= (int)$page ?>"><?= (int)$page ?></a><?php endforeach; ?><?php if(isset($paginationNext)): ?><a class="vo-btn" rel="next" href="<?= $h($paginationNext) ?>">Página siguiente</a><?php endif; ?></div></nav>
